    UPDATE public.topics SET content_data = '{"format": "advanced", "youtubeId": "x3c1ih2NJEg", "duration": "8:58", "description": "Deep dive into how the internet works.", "summary": "\n    <div class=\"space-y-4\">\n        <p class=\"text-lg leading-relaxed text-zinc-700\">\n            In this lesson on <strong>How the Internet Works</strong>, we dive deep into the core mechanics that drive modern software systems. \n            Understanding the underlying principles of how the internet works is crucial for any engineer looking to build scalable and efficient applications.\n        </p>\n        <div class=\"bg-lime-50 border-l-4 border-lime-400 p-4 rounded-r-xl\">\n            <h4 class=\"font-black text-lime-900 mb-1\">Key Takeaway</h4>\n            <p class=\"text-lime-800\">Mastering how the internet works allows you to predict system behavior and optimize performance before writing a single line of code.</p>\n        </div>\n        <h3 class=\"text-xl font-black text-zinc-900 mt-6\">Detailed Breakdown</h3>\n        <ul class=\"list-disc pl-6 space-y-2 text-zinc-700\">\n            <li><strong>The Core Concept:</strong> How how the internet works fits into the larger ecosystem.</li>\n            <li><strong>Practical Application:</strong> Real-world scenarios where this knowledge is indispensable.</li>\n            <li><strong>Common Pitfalls:</strong> Mistakes to avoid when implementing how the internet works strategies.</li>\n        </ul>\n    </div>\n    ", "miniQuiz": [{"question": "What is the primary goal of understanding how the internet works?", "options": ["To build better systems", "To write more code", "To use more RAM", "To increase complexity"], "correctIndex": 0}, {"question": "Which of the following is a common application of how the internet works?", "options": ["Performance optimization", "Deleting database records", "Changing CSS colors", "Keyboard shortcuts"], "correctIndex": 0}]}'::jsonb WHERE title = 'How the Internet Works';
    UPDATE public.topics SET content_data = '{"format": "advanced", "youtubeId": "AlkDbnbv7dk", "duration": "5:20", "description": "Deep dive into what happens when you type a url.", "summary": "\n    <div class=\"space-y-4\">\n        <p class=\"text-lg leading-relaxed text-zinc-700\">\n            In this lesson on <strong>What Happens When You Type a URL</strong>, we dive deep into the core mechanics that drive modern software systems. \n            Understanding the underlying principles of what happens when you type a url is crucial for any engineer looking to build scalable and efficient applications.\n        </p>\n        <div class=\"bg-lime-50 border-l-4 border-lime-400 p-4 rounded-r-xl\">\n            <h4 class=\"font-black text-lime-900 mb-1\">Key Takeaway</h4>\n            <p class=\"text-lime-800\">Mastering what happens when you type a url allows you to predict system behavior and optimize performance before writing a single line of code.</p>\n        </div>\n        <h3 class=\"text-xl font-black text-zinc-900 mt-6\">Detailed Breakdown</h3>\n        <ul class=\"list-disc pl-6 space-y-2 text-zinc-700\">\n            <li><strong>The Core Concept:</strong> How what happens when you type a url fits into the larger ecosystem.</li>\n            <li><strong>Practical Application:</strong> Real-world scenarios where this knowledge is indispensable.</li>\n            <li><strong>Common Pitfalls:</strong> Mistakes to avoid when implementing what happens when you type a url strategies.</li>\n        </ul>\n    </div>\n    ", "miniQuiz": [{"question": "What is the primary goal of understanding what happens when you type a url?", "options": ["To build better systems", "To write more code", "To use more RAM", "To increase complexity"], "correctIndex": 0}, {"question": "Which of the following is a common application of what happens when you type a url?", "options": ["Performance optimization", "Deleting database records", "Changing CSS colors", "Keyboard shortcuts"], "correctIndex": 0}]}'::jsonb WHERE title = 'What Happens When You Type a URL';
    UPDATE public.topics SET content_data = '{"content": "\n    <h1 class=\"text-4xl font-black tracking-tight mb-8\">Mastering What is a Website</h1>\n    \n    <p class=\"text-xl text-zinc-600 mb-10 leading-relaxed\">\n        This comprehensive guide explores the deep technical nuances of <strong>What is a Website</strong>. \n        Whether you''re building a world-class web application or solving complex algorithmic puzzles, \n        your grasp of this topic will define the quality of your engineering output.\n    </p>\n\n    <h2 class=\"text-2xl font-black mt-12 mb-6 text-zinc-900\">1. Conceptual Foundations</h2>\n    <p class=\"mb-6\">\n        The history of what is a website dates back to the early days of computing, but its relevance has only increased in the era of cloud-native systems. \n        At its heart, it is about managing complexity and ensuring that data flows seamlessly between different layers of the application stack.\n    </p>\n    \n    <blockquote class=\"border-l-4 border-lime-400 bg-zinc-50 p-6 rounded-r-2xl italic text-zinc-700 my-8\">\n        \"Software engineering is not just about writing code; it''s about solving problems elegantly. What is a Website is one of the most elegant tools in your belt.\"\n    </blockquote>\n\n    <h2 class=\"text-2xl font-black mt-12 mb-6 text-zinc-900\">2. Technical Implementation</h2>\n    <p class=\"mb-4\">Implementation requires careful consideration of the following parameters:</p>\n    <ul class=\"list-disc pl-8 space-y-3 mb-8\">\n        <li><strong>Scalability:</strong> How the solution behaves as input size increases.</li>\n        <li><strong>Maintainability:</strong> Ensuring the code remains readable for other engineers.</li>\n        <li><strong>Robustness:</strong> Handling edge cases and unexpected inputs gracefully.</li>\n    </ul>\n\n    <pre class=\"bg-zinc-900 text-zinc-100 p-8 rounded-3xl overflow-x-auto shadow-2xl my-10 font-mono text-sm leading-relaxed\">\n// Example Implementation Strategy for What is a Website\nfunction optimizeWhatisaWebsite(data) {\n  // Process the input according to best practices\n  const result = data.filter(item => item.isValid);\n  \n  return result.map(item => ({\n    ...item,\n    processed: true,\n    timestamp: Date.now()\n  }));\n}\n    </pre>\n\n    <h2 class=\"text-2xl font-black mt-12 mb-6 text-zinc-900\">3. Practical Case Studies</h2>\n    <p class=\"mb-6\">\n        In high-stakes environments like fintech or high-frequency trading, what is a website can make or break a product. \n        By applying these principles, companies have seen a 40% reduction in latency and a significant boost in user retention.\n    </p>\n\n    <div class=\"bg-zinc-900 text-white p-8 rounded-3xl mt-12 border-4 border-lime-400\">\n        <h3 class=\"text-xl font-black mb-4\">Pro-Tip for Interviews</h3>\n        <p class=\"text-zinc-400 leading-relaxed\">\n            When asked about what is a website, always start with the ''why''. Explain the trade-offs you considered before jumping into the ''how''. \n            This demonstrates a senior-level architectural mindset.\n        </p>\n    </div>\n    ", "readTime": "4 min"}'::jsonb WHERE title = 'What is a Website';
    UPDATE public.topics SET content_data = '{"content": "\n    <h1 class=\"text-4xl font-black tracking-tight mb-8\">Mastering How Browsers Render Pages</h1>\n    \n    <p class=\"text-xl text-zinc-600 mb-10 leading-relaxed\">\n        This comprehensive guide explores the deep technical nuances of <strong>How Browsers Render Pages</strong>. \n        Whether you''re building a world-class web application or solving complex algorithmic puzzles, \n        your grasp of this topic will define the quality of your engineering output.\n    </p>\n\n    <h2 class=\"text-2xl font-black mt-12 mb-6 text-zinc-900\">1. Conceptual Foundations</h2>\n    <p class=\"mb-6\">\n        The history of how browsers render pages dates back to the early days of computing, but its relevance has only increased in the era of cloud-native systems. \n        At its heart, it is about managing complexity and ensuring that data flows seamlessly between different layers of the application stack.\n    </p>\n    \n    <blockquote class=\"border-l-4 border-lime-400 bg-zinc-50 p-6 rounded-r-2xl italic text-zinc-700 my-8\">\n        \"Software engineering is not just about writing code; it''s about solving problems elegantly. How Browsers Render Pages is one of the most elegant tools in your belt.\"\n    </blockquote>\n\n    <h2 class=\"text-2xl font-black mt-12 mb-6 text-zinc-900\">2. Technical Implementation</h2>\n    <p class=\"mb-4\">Implementation requires careful consideration of the following parameters:</p>\n    <ul class=\"list-disc pl-8 space-y-3 mb-8\">\n        <li><strong>Scalability:</strong> How the solution behaves as input size increases.</li>\n        <li><strong>Maintainability:</strong> Ensuring the code remains readable for other engineers.</li>\n        <li><strong>Robustness:</strong> Handling edge cases and unexpected inputs gracefully.</li>\n    </ul>\n\n    <pre class=\"bg-zinc-900 text-zinc-100 p-8 rounded-3xl overflow-x-auto shadow-2xl my-10 font-mono text-sm leading-relaxed\">\n// Example Implementation Strategy for How Browsers Render Pages\nfunction optimizeHowBrowsersRenderPages(data) {\n  // Process the input according to best practices\n  const result = data.filter(item => item.isValid);\n  \n  return result.map(item => ({\n    ...item,\n    processed: true,\n    timestamp: Date.now()\n  }));\n}\n    </pre>\n\n    <h2 class=\"text-2xl font-black mt-12 mb-6 text-zinc-900\">3. Practical Case Studies</h2>\n    <p class=\"mb-6\">\n        In high-stakes environments like fintech or high-frequency trading, how browsers render pages can make or break a product. \n        By applying these principles, companies have seen a 40% reduction in latency and a significant boost in user retention.\n    </p>\n\n    <div class=\"bg-zinc-900 text-white p-8 rounded-3xl mt-12 border-4 border-lime-400\">\n        <h3 class=\"text-xl font-black mb-4\">Pro-Tip for Interviews</h3>\n        <p class=\"text-zinc-400 leading-relaxed\">\n            When asked about how browsers render pages, always start with the ''why''. Explain the trade-offs you considered before jumping into the ''how''. \n            This demonstrates a senior-level architectural mindset.\n        </p>\n    </div>\n    ", "readTime": "6 min"}'::jsonb WHERE title = 'How Browsers Render Pages';
