    UPDATE public.topics SET content_data = '{"format": "advanced", "youtubeId": "aK3C3j6xI6c", "duration": "6:10", "description": "Deep dive into decision making in programs.", "summary": "\n    <div class=\"space-y-4\">\n        <p class=\"text-lg leading-relaxed text-zinc-700\">\n            In this lesson on <strong>Decision Making in Programs</strong>, we dive deep into the core mechanics that drive modern software systems. \n            Understanding the underlying principles of decision making in programs is crucial for any engineer looking to build scalable and efficient applications.\n        </p>\n        <div class=\"bg-lime-50 border-l-4 border-lime-400 p-4 rounded-r-xl\">\n            <h4 class=\"font-black text-lime-900 mb-1\">Key Takeaway</h4>\n            <p class=\"text-lime-800\">Mastering decision making in programs allows you to predict system behavior and optimize performance before writing a single line of code.</p>\n        </div>\n        <h3 class=\"text-xl font-black text-zinc-900 mt-6\">Detailed Breakdown</h3>\n        <ul class=\"list-disc pl-6 space-y-2 text-zinc-700\">\n            <li><strong>The Core Concept:</strong> How decision making in programs fits into the larger ecosystem.</li>\n            <li><strong>Practical Application:</strong> Real-world scenarios where this knowledge is indispensable.</li>\n            <li><strong>Common Pitfalls:</strong> Mistakes to avoid when implementing decision making in programs strategies.</li>\n        </ul>\n    </div>\n    ", "miniQuiz": [{"question": "What is the primary goal of understanding decision making in programs?", "options": ["To build better systems", "To write more code", "To use more RAM", "To increase complexity"], "correctIndex": 0}, {"question": "Which of the following is a common application of decision making in programs?", "options": ["Performance optimization", "Deleting database records", "Changing CSS colors", "Keyboard shortcuts"], "correctIndex": 0}]}'::jsonb WHERE ti